import React, { useState, useCallback } from 'react';
import { generateServerFiles, packageAsExecutable, downloadGeneratedServer } from '../../utils/gatewayGenerator';

interface ProtocolConfig {
  id: string;
  name: string;
  type: 'modbus-tcp' | 'modbus-rtu' | 'modbus-serial' | 'opcua' | 'mqtt' | 'http-rest' | 'ethernet-ip' | 'bacnet';
  enabled: boolean;
  mode: 'client' | 'server'; // New field for client/server mode
  settings: Record<string, any>;
}

interface GatewayConfig {
  name: string;
  description: string;
  version: string;
  protocols: ProtocolConfig[];
  server: {
    port: number;
    host: string;
    ssl: boolean;
    authentication: boolean;
  };
  logging: {
    level: 'debug' | 'info' | 'warn' | 'error';
    file: boolean;
    console: boolean;
  };
}

const defaultGatewayConfig: GatewayConfig = {
  name: 'Industrial Gateway Server',
  description: 'Auto-generated protocol gateway server',
  version: '1.0.0',
  protocols: [
    {
      id: 'modbus-tcp-1',
      name: 'Modbus TCP',
      type: 'modbus-tcp',
      enabled: true,
      settings: {
        port: 502,
        timeout: 5000,
        retries: 3,
        devices: [
          {
            name: 'PLC-1',
            ip: '192.168.1.100',
            port: 502,
            slaveId: 1,
            registers: {
              holdingRegisters: { start: 0, count: 100 },
              coils: { start: 0, count: 64 },
              inputRegisters: { start: 0, count: 50 }
            }
          }
        ]
      }
    }
  ],
  server: {
    port: 8080,
    host: '0.0.0.0',
    ssl: false,
    authentication: false
  },
  logging: {
    level: 'info',
    file: true,
    console: true
  }
};

const GatewayBuilder: React.FC = () => {
  const [config, setConfig] = useState<GatewayConfig>(defaultGatewayConfig);
  const [activeProtocol, setActiveProtocol] = useState<string>('modbus-tcp-1');
  const [isGenerating, setIsGenerating] = useState<boolean>(false);
  const [generationStatus, setGenerationStatus] = useState<string>('');

  const updateConfig = useCallback((updates: Partial<GatewayConfig>) => {
    setConfig(prev => ({ ...prev, ...updates }));
  }, []);

  const updateProtocol = useCallback((protocolId: string, updates: Partial<ProtocolConfig>) => {
    setConfig(prev => ({
      ...prev,
      protocols: prev.protocols.map(protocol =>
        protocol.id === protocolId ? { ...protocol, ...updates } : protocol
      )
    }));
  }, []);

  const addProtocol = useCallback((type: ProtocolConfig['type']) => {
    const newProtocol: ProtocolConfig = {
      id: `${type}-${Date.now()}`,
      name: `${type.toUpperCase()} Protocol`,
      type,
      enabled: true,
      settings: getDefaultProtocolSettings(type)
    };

    setConfig(prev => ({
      ...prev,
      protocols: [...prev.protocols, newProtocol]
    }));
  }, []);

  const removeProtocol = useCallback((protocolId: string) => {
    setConfig(prev => ({
      ...prev,
      protocols: prev.protocols.filter(p => p.id !== protocolId)
    }));
  }, []);

  const generateGatewayServer = useCallback(async () => {
    setIsGenerating(true);
    setGenerationStatus('Generating server code...');

    try {
      // Generate server files
      const serverFiles = await generateServerFiles(config);
      
      setGenerationStatus('Packaging executable...');
      
      // Package as executable
      const blob = await packageAsExecutable(serverFiles, config);
      
      setGenerationStatus('✅ Gateway server generated successfully!');
      
      // Download the generated files
      downloadGeneratedServer(config, blob);
      
    } catch (error) {
      console.error('Generation failed:', error);
      setGenerationStatus(`❌ Generation failed: ${error instanceof Error ? error.message : String(error)}`);
    } finally {
      setIsGenerating(false);
    }
  }, [config]);

  const activeProtocolConfig = config.protocols.find(p => p.id === activeProtocol);

  return (
    <div style={{
      display: 'flex',
      height: '100vh',
      backgroundColor: '#f8f9fa',
      fontFamily: '"Segoe UI", "Arial", sans-serif'
    }}>
      {/* Left Panel - Protocol Configuration */}
      <div style={{
        width: '350px',
        backgroundColor: '#ffffff',
        borderRight: '1px solid #dee2e6',
        display: 'flex',
        flexDirection: 'column'
      }}>
        {/* Header */}
        <div style={{
          padding: '20px',
          borderBottom: '1px solid #dee2e6'
        }}>
          <h2 style={{ margin: '0 0 8px 0', fontSize: '18px', fontWeight: '600', color: '#495057' }}>
            🏭 Gateway Builder
          </h2>
          <p style={{ margin: 0, fontSize: '13px', color: '#6c757d' }}>
            Configure and generate industrial protocol gateway servers
          </p>
        </div>

        {/* Server Configuration */}
        <div style={{
          padding: '16px 20px',
          borderBottom: '1px solid #dee2e6'
        }}>
          <h3 style={{ margin: '0 0 12px 0', fontSize: '14px', fontWeight: '600', color: '#495057' }}>
            Server Settings
          </h3>
          
          <div style={{ marginBottom: '12px' }}>
            <label style={{ display: 'block', fontSize: '12px', fontWeight: '500', color: '#495057', marginBottom: '4px' }}>
              Server Name
            </label>
            <input
              type="text"
              value={config.name}
              onChange={(e) => updateConfig({ name: e.target.value })}
              style={{
                width: '100%',
                padding: '6px 8px',
                border: '1px solid #ced4da',
                borderRadius: '4px',
                fontSize: '12px'
              }}
            />
          </div>

          <div style={{ display: 'flex', gap: '8px', marginBottom: '12px' }}>
            <div style={{ flex: 1 }}>
              <label style={{ display: 'block', fontSize: '12px', fontWeight: '500', color: '#495057', marginBottom: '4px' }}>
                Port
              </label>
              <input
                type="number"
                value={config.server.port}
                onChange={(e) => updateConfig({ 
                  server: { ...config.server, port: parseInt(e.target.value) || 8080 }
                })}
                style={{
                  width: '100%',
                  padding: '6px 8px',
                  border: '1px solid #ced4da',
                  borderRadius: '4px',
                  fontSize: '12px'
                }}
              />
            </div>
            <div style={{ flex: 2 }}>
              <label style={{ display: 'block', fontSize: '12px', fontWeight: '500', color: '#495057', marginBottom: '4px' }}>
                Host
              </label>
              <input
                type="text"
                value={config.server.host}
                onChange={(e) => updateConfig({ 
                  server: { ...config.server, host: e.target.value }
                })}
                style={{
                  width: '100%',
                  padding: '6px 8px',
                  border: '1px solid #ced4da',
                  borderRadius: '4px',
                  fontSize: '12px'
                }}
              />
            </div>
          </div>
        </div>

        {/* Protocols List */}
        <div style={{
          flex: 1,
          overflowY: 'auto'
        }}>
          <div style={{ padding: '16px 20px 12px 20px' }}>
            <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between', marginBottom: '12px' }}>
              <h3 style={{ margin: 0, fontSize: '14px', fontWeight: '600', color: '#495057' }}>
                Protocols ({config.protocols.length})
              </h3>
              <div style={{ position: 'relative' }}>
                <button
                  onClick={() => {
                    addProtocol('modbus-tcp');
                  }}
                  style={{
                    padding: '4px 8px',
                    fontSize: '11px',
                    border: '1px solid #28a745',
                    borderRadius: '4px',
                    backgroundColor: '#28a745',
                    color: 'white',
                    cursor: 'pointer'
                  }}
                >
                  + Add Modbus TCP
                </button>
              </div>
            </div>

            {config.protocols.map(protocol => (
              <div
                key={protocol.id}
                onClick={() => setActiveProtocol(protocol.id)}
                style={{
                  padding: '10px 12px',
                  marginBottom: '6px',
                  backgroundColor: activeProtocol === protocol.id ? '#e3f2fd' : '#f8f9fa',
                  border: activeProtocol === protocol.id ? '2px solid #0066cc' : '1px solid #dee2e6',
                  borderRadius: '4px',
                  cursor: 'pointer',
                  transition: 'all 0.2s ease'
                }}
              >
                <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between' }}>
                  <div style={{ flex: 1 }}>
                    <div style={{
                      fontSize: '12px',
                      fontWeight: '500',
                      color: activeProtocol === protocol.id ? '#0066cc' : '#495057',
                      marginBottom: '2px'
                    }}>
                      {protocol.name}
                    </div>
                    <div style={{ fontSize: '10px', color: '#6c757d' }}>
                      {protocol.type.toUpperCase()} • {protocol.enabled ? 'Enabled' : 'Disabled'}
                    </div>
                  </div>
                  <div style={{ display: 'flex', gap: '4px' }}>
                    <button
                      onClick={(e) => {
                        e.stopPropagation();
                        updateProtocol(protocol.id, { enabled: !protocol.enabled });
                      }}
                      style={{
                        padding: '2px 6px',
                        fontSize: '10px',
                        border: 'none',
                        borderRadius: '3px',
                        backgroundColor: protocol.enabled ? '#28a745' : '#6c757d',
                        color: 'white',
                        cursor: 'pointer'
                      }}
                    >
                      {protocol.enabled ? 'ON' : 'OFF'}
                    </button>
                    <button
                      onClick={(e) => {
                        e.stopPropagation();
                        removeProtocol(protocol.id);
                      }}
                      style={{
                        padding: '2px 6px',
                        fontSize: '10px',
                        border: 'none',
                        borderRadius: '3px',
                        backgroundColor: '#dc3545',
                        color: 'white',
                        cursor: 'pointer'
                      }}
                    >
                      ×
                    </button>
                  </div>
                </div>
              </div>
            ))}
          </div>
        </div>

        {/* Generate Button */}
        <div style={{
          padding: '20px',
          borderTop: '1px solid #dee2e6'
        }}>
          <button
            onClick={generateGatewayServer}
            disabled={isGenerating || config.protocols.length === 0}
            style={{
              width: '100%',
              padding: '12px',
              backgroundColor: isGenerating ? '#6c757d' : '#0066cc',
              color: 'white',
              border: 'none',
              borderRadius: '4px',
              fontSize: '14px',
              fontWeight: '500',
              cursor: isGenerating ? 'not-allowed' : 'pointer',
              display: 'flex',
              alignItems: 'center',
              justifyContent: 'center',
              gap: '8px'
            }}
          >
            {isGenerating ? (
              <>
                <div style={{ 
                  width: '16px', 
                  height: '16px', 
                  border: '2px solid transparent',
                  borderTop: '2px solid white',
                  borderRadius: '50%',
                  animation: 'spin 1s linear infinite'
                }} />
                Generating...
              </>
            ) : (
              <>
                � Generate EXE Server
              </>
            )}
          </button>
          
          {generationStatus && (
            <div style={{
              marginTop: '8px',
              padding: '8px',
              backgroundColor: generationStatus.includes('❌') ? '#f8d7da' : '#d4edda',
              border: `1px solid ${generationStatus.includes('❌') ? '#f5c6cb' : '#c3e6cb'}`,
              borderRadius: '4px',
              fontSize: '11px',
              color: generationStatus.includes('❌') ? '#721c24' : '#155724'
            }}>
              {generationStatus}
            </div>
          )}
        </div>
      </div>

      {/* Right Panel - Protocol Details */}
      <div style={{
        flex: 1,
        display: 'flex',
        flexDirection: 'column'
      }}>
        {activeProtocolConfig ? (
          <ProtocolConfigPanel
            protocol={activeProtocolConfig}
            onUpdate={(updates) => updateProtocol(activeProtocolConfig.id, updates)}
          />
        ) : (
          <div style={{
            flex: 1,
            display: 'flex',
            alignItems: 'center',
            justifyContent: 'center',
            flexDirection: 'column',
            color: '#6c757d'
          }}>
            <div style={{ fontSize: '48px', marginBottom: '16px' }}>🔧</div>
            <h3 style={{ margin: '0 0 8px 0', fontSize: '16px' }}>Select a Protocol</h3>
            <p style={{ margin: 0, fontSize: '14px', textAlign: 'center' }}>
              Choose a protocol from the left panel to configure its settings
            </p>
          </div>
        )}
      </div>
    </div>
  );
};

// Protocol Configuration Panel Component
interface ProtocolConfigPanelProps {
  protocol: ProtocolConfig;
  onUpdate: (updates: Partial<ProtocolConfig>) => void;
}

const ProtocolConfigPanel: React.FC<ProtocolConfigPanelProps> = ({ protocol, onUpdate }) => {
  const updateSettings = useCallback((updates: Record<string, any>) => {
    onUpdate({
      settings: { ...protocol.settings, ...updates }
    });
  }, [protocol.settings, onUpdate]);

  return (
    <div style={{
      flex: 1,
      display: 'flex',
      flexDirection: 'column'
    }}>
      {/* Header */}
      <div style={{
        padding: '20px',
        backgroundColor: '#ffffff',
        borderBottom: '1px solid #dee2e6'
      }}>
        <h2 style={{ margin: '0 0 8px 0', fontSize: '18px', fontWeight: '600', color: '#495057' }}>
          {protocol.name} Configuration
        </h2>
        <p style={{ margin: 0, fontSize: '13px', color: '#6c757d' }}>
          Configure settings for {protocol.type.toUpperCase()} protocol
        </p>
      </div>

      {/* Configuration Content */}
      <div style={{
        flex: 1,
        padding: '20px',
        overflowY: 'auto',
        backgroundColor: '#f8f9fa'
      }}>
        {protocol.type === 'modbus-tcp' && (
          <ModbusTcpConfig
            settings={protocol.settings}
            onUpdate={updateSettings}
          />
        )}
        {protocol.type === 'opcua' && (
          <div style={{ padding: '20px', textAlign: 'center', color: '#6c757d' }}>
            OPC UA configuration coming soon...
          </div>
        )}
        {protocol.type === 'mqtt' && (
          <div style={{ padding: '20px', textAlign: 'center', color: '#6c757d' }}>
            MQTT configuration coming soon...
          </div>
        )}
      </div>
    </div>
  );
};

// Modbus TCP Configuration Component
interface ModbusTcpConfigProps {
  settings: any;
  onUpdate: (updates: Record<string, any>) => void;
}

const ModbusTcpConfig: React.FC<ModbusTcpConfigProps> = ({ settings, onUpdate }) => {
  return (
    <div>
      {/* Global Settings */}
      <div style={{
        backgroundColor: '#ffffff',
        border: '1px solid #dee2e6',
        borderRadius: '6px',
        padding: '16px',
        marginBottom: '16px'
      }}>
        <h4 style={{ margin: '0 0 12px 0', fontSize: '14px', fontWeight: '600', color: '#495057' }}>
          Global Settings
        </h4>
        
        <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr 1fr', gap: '12px' }}>
          <div>
            <label style={{ display: 'block', fontSize: '12px', fontWeight: '500', color: '#495057', marginBottom: '4px' }}>
              Timeout (ms)
            </label>
            <input
              type="number"
              value={settings.timeout || 5000}
              onChange={(e) => onUpdate({ timeout: parseInt(e.target.value) || 5000 })}
              style={{
                width: '100%',
                padding: '6px 8px',
                border: '1px solid #ced4da',
                borderRadius: '4px',
                fontSize: '12px'
              }}
            />
          </div>
          
          <div>
            <label style={{ display: 'block', fontSize: '12px', fontWeight: '500', color: '#495057', marginBottom: '4px' }}>
              Retries
            </label>
            <input
              type="number"
              value={settings.retries || 3}
              onChange={(e) => onUpdate({ retries: parseInt(e.target.value) || 3 })}
              style={{
                width: '100%',
                padding: '6px 8px',
                border: '1px solid #ced4da',
                borderRadius: '4px',
                fontSize: '12px'
              }}
            />
          </div>
          
          <div>
            <label style={{ display: 'block', fontSize: '12px', fontWeight: '500', color: '#495057', marginBottom: '4px' }}>
              Port
            </label>
            <input
              type="number"
              value={settings.port || 502}
              onChange={(e) => onUpdate({ port: parseInt(e.target.value) || 502 })}
              style={{
                width: '100%',
                padding: '6px 8px',
                border: '1px solid #ced4da',
                borderRadius: '4px',
                fontSize: '12px'
              }}
            />
          </div>
        </div>
      </div>

      {/* Devices */}
      <div style={{
        backgroundColor: '#ffffff',
        border: '1px solid #dee2e6',
        borderRadius: '6px',
        padding: '16px'
      }}>
        <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between', marginBottom: '12px' }}>
          <h4 style={{ margin: 0, fontSize: '14px', fontWeight: '600', color: '#495057' }}>
            Modbus Devices ({(settings.devices || []).length})
          </h4>
          <button
            onClick={() => {
              const newDevice = {
                name: `Device-${Date.now()}`,
                ip: '192.168.1.100',
                port: 502,
                slaveId: 1,
                registers: {
                  holdingRegisters: { start: 0, count: 100 },
                  coils: { start: 0, count: 64 },
                  inputRegisters: { start: 0, count: 50 }
                }
              };
              onUpdate({
                devices: [...(settings.devices || []), newDevice]
              });
            }}
            style={{
              padding: '4px 8px',
              fontSize: '11px',
              backgroundColor: '#28a745',
              color: 'white',
              border: 'none',
              borderRadius: '4px',
              cursor: 'pointer'
            }}
          >
            + Add Device
          </button>
        </div>

        {(settings.devices || []).map((device: any, index: number) => (
          <div
            key={index}
            style={{
              border: '1px solid #e9ecef',
              borderRadius: '4px',
              padding: '12px',
              marginBottom: '8px',
              backgroundColor: '#f8f9fa'
            }}
          >
            <div style={{ display: 'grid', gridTemplateColumns: '2fr 1fr 1fr 1fr auto', gap: '8px', alignItems: 'center' }}>
              <input
                type="text"
                value={device.name}
                onChange={(e) => {
                  const updatedDevices = [...(settings.devices || [])];
                  updatedDevices[index] = { ...device, name: e.target.value };
                  onUpdate({ devices: updatedDevices });
                }}
                placeholder="Device name"
                style={{
                  padding: '6px 8px',
                  border: '1px solid #ced4da',
                  borderRadius: '3px',
                  fontSize: '11px'
                }}
              />
              
              <input
                type="text"
                value={device.ip}
                onChange={(e) => {
                  const updatedDevices = [...(settings.devices || [])];
                  updatedDevices[index] = { ...device, ip: e.target.value };
                  onUpdate({ devices: updatedDevices });
                }}
                placeholder="IP Address"
                style={{
                  padding: '6px 8px',
                  border: '1px solid #ced4da',
                  borderRadius: '3px',
                  fontSize: '11px'
                }}
              />
              
              <input
                type="number"
                value={device.port}
                onChange={(e) => {
                  const updatedDevices = [...(settings.devices || [])];
                  updatedDevices[index] = { ...device, port: parseInt(e.target.value) || 502 };
                  onUpdate({ devices: updatedDevices });
                }}
                placeholder="Port"
                style={{
                  padding: '6px 8px',
                  border: '1px solid #ced4da',
                  borderRadius: '3px',
                  fontSize: '11px'
                }}
              />
              
              <input
                type="number"
                value={device.slaveId}
                onChange={(e) => {
                  const updatedDevices = [...(settings.devices || [])];
                  updatedDevices[index] = { ...device, slaveId: parseInt(e.target.value) || 1 };
                  onUpdate({ devices: updatedDevices });
                }}
                placeholder="Slave ID"
                style={{
                  padding: '6px 8px',
                  border: '1px solid #ced4da',
                  borderRadius: '3px',
                  fontSize: '11px'
                }}
              />
              
              <button
                onClick={() => {
                  const updatedDevices = (settings.devices || []).filter((_: any, i: number) => i !== index);
                  onUpdate({ devices: updatedDevices });
                }}
                style={{
                  padding: '4px 6px',
                  fontSize: '10px',
                  backgroundColor: '#dc3545',
                  color: 'white',
                  border: 'none',
                  borderRadius: '3px',
                  cursor: 'pointer'
                }}
              >
                ×
              </button>
            </div>
          </div>
        ))}
      </div>
    </div>
  );
};

// Helper Functions
function getDefaultProtocolSettings(type: ProtocolConfig['type']): Record<string, any> {
  switch (type) {
    case 'modbus-tcp':
      return {
        port: 502,
        timeout: 5000,
        retries: 3,
        devices: []
      };
    case 'opcua':
      return {
        endpoint: 'opc.tcp://localhost:4840',
        securityMode: 'None',
        securityPolicy: 'None'
      };
    case 'mqtt':
      return {
        broker: 'mqtt://localhost:1883',
        clientId: 'gateway-client',
        topics: []
      };
    default:
      return {};
  }
}

export default GatewayBuilder;
